{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income limits (2025): 1 person: $2,815; 2 people: $3,681; 3 people: $4,547; 4 people: $5,414; 5 people: $6,280; 6 people: $7,146. Equivalent to at or below 150% of Federal Poverty Guidelines. Automatic eligibility if enrolled in SNAP, SSI, TANF, or certain veterans' programs. Applies to homeowners and renters; public/subsidized housing eligibility varies by payment of energy costs.[1][2][3][8]",
    "asset_limits": "No asset limit.[1]",
    "other_requirements": ["Household includes all at address sharing utility bill.", "U.S. citizen or qualified non-citizen in household.", "Financial need demonstrated, especially for crisis assistance (e.g., shutoff notice, broken equipment)."]
  },
  "benefits": {
    "type": "financial",
    "value": "Heating: $1-$12,300; Cooling: $1-$12,300; Crisis: up to $2,400. Payments go directly to utility providers. Also includes energy education and efficiency measures via CEAP integration.[1][6]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Phone: (877) 399-8939 or 211.", "Website: 211Texas.org to find local agency.", "In-person/mail: Local community action agencies/CEAP subrecipients covering all 254 counties (e.g., Travis County CEAP: (512) 584-4120).", "Online account with utility (e.g., Texas Gas Service) recommended to speed documentation."],
    "processing_time": "Varies by agency; placed on waitlist upon submission, caseworker calls when turn arrives.[4]",
    "waitlist": "Yes, common; applications placed in line by site, processed when funding available.[4]",
    "forms": ["Local agency-specific CEAP application forms."],
    "documents": ["Proof of income (pay stubs, benefit letters).", "Proof of residency/utility bills (recent statements downloadable from utility account).", "ID for all household members.", "Social Security numbers.", "Proof of energy crisis if applicable (shutoff notice)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in all 254 counties via subrecipients.",
    "regional_variations": "Administered by multiple local community action agencies/CEAP providers with varying offices, wait times, and processing. E.g., Travis County has 7 locations open 8am-5pm weekdays.[4][6]",
    "offices_or_providers": ["Contact via 211Texas.org or (877) 399-8939 for local subrecipient."]
  },
  "official_source": "https://www.tdhca.texas.gov/comprehensive-energy-assistance-program-ceap",
  "gotchas": ["Not year-round: heating (fall/winter), cooling (summer), crisis (emergencies only).[1]", "Funding limited by federal availability; subject to waitlists.[4]", "Household defined broadly (all sharing utility bill, unlike SNAP).[1]", "Must contact specific local agency; no central statewide application.[4][6]", "Public/subsidized housing eligibility depends on how energy costs are paid.[2][3]"],
  "data_shape_notes": "Administered via 254 county subrecipients with regional variations in providers and waitlists; benefits via CEAP integration; income at 150% FPG, no asset test; seasonal components."
}

{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all Medicare-eligible individuals regardless of income[1][2]",
    "asset_limits": "No asset limits; no financial tests apply[1][2]",
    "other_requirements": ["Must be eligible for Medicare (typically age 65+ or under 65 with disabilities), soon-to-be eligible, family members, or caregivers of Medicare beneficiaries[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling and assistance on Medicare options (Parts A, B, C, D), Medigap, plan reviews, applying for low-income programs (Medicare Savings Programs, Extra Help/LIS, Medicaid), claims/billing resolution, enrollment help, public education presentations, outreach events, and fraud prevention via Senior Medicare Patrol (SMP)[2][4][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-252-9240 (Texas HICAP)[8]", "Website: shiphelp.org (use SHIP Locator for Texas), Texas-specific website via shiphelp.org/ships/texas/[8][9]", "In-person or phone counseling via local SHIP sites (find via shiphelp.org or 1-877-839-2675 national line)[1][8]"],
    "processing_time": "Immediate assistance available via phone or scheduled appointments; no formal application processing[1][4]",
    "waitlist": null,
    "forms": ["No specific forms required for SHIP counseling; counselors assist with Medicare-related forms during sessions[2]"],
    "documents": ["Medicare card, current health/prescription drug plan details, income info if applying for savings programs via SHIP help, questions or issues list[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to Medicare-eligible[3][8]",
    "regional_variations": "Delivered through local network of over 2,200 sites nationwide partnering with Texas Area Agencies on Aging and community organizations; specific providers/offices vary by region but services standardized[2][5]",
    "offices_or_providers": ["Local sites via Texas Health Information, Counseling, and Advocacy Program (HICAP); find via 1-800-252-9240 or shiphelp.org[8]"]
  },
  "official_source": "https://www.shiphelp.org/ships/texas/ (Texas SHIP page); national: https://acl.gov/programs/connecting-people-services/state-health-insurance-assistance-program-ship[2][8]",
  "gotchas": ["Not a healthcare or financial benefit provider—only free counseling/advocacy; people mistake it for direct aid[1][4]", "Services are free but appointment-based in some areas; contact early (e.g., 3 months before Medicare eligibility)[1]", "Assists with low-income programs but eligibility for those separate (e.g., MSP/LIS have income/asset tests)[2]", "Operated as HICAP in Texas—use state-specific contact[8]"],
  "data_shape_notes": "no income/asset test for counseling access; statewide via regional local partners; service-based not financial aid; open to Medicare families/caregivers[1][2][3][8]"
}

