{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all residents regardless of financial status.",
    "asset_limits": "No asset limits; no financial eligibility requirements.",
    "other_requirements": ["Resident must live in a Texas nursing facility or assisted living facility.", "Services also extend to certain caregivers and family members of persons 60 years of age or older.", "For developmental disabilities in state supported living centers, contact separate Office of the Independent Ombudsman."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy for residents' rights including protection from abuse, restraints, and discrimination; privacy and visitation rights; informed consent on services and costs; no unwarranted transfers or discharges; complaint resolution without reprisal; assistance with personal affairs, advance directives, and grievances. Ombudsmen investigate complaints, monitor care quality, participate in hearings, and ensure access to records and inspection reports.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-252-2412 to speak with an LTC Ombudsman in your area.", "Website: https://ltco.texas.gov (find local ombudsman or email office).", "Local programs (varies by region, e.g., contact Cizik School of Nursing for Harris County or The Senior Source for Dallas County)."],
    "processing_time": "Immediate response for complaints and advocacy; no formal processing as services are provided on-demand.",
    "waitlist": null,
    "forms": ["No specific application form for residents; HHSC form used internally for program operations (not required for families)."],
    "documents": ["No documents needed to contact or receive services; provide details of concerns or facility name when calling."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to nursing facilities and assisted living facilities statewide; excludes state supported living centers for developmental disabilities.",
    "regional_variations": "Administered locally by different agencies (e.g., Cizik School of Nursing in Harris County, The Senior Source in Dallas County, Texoma Council of Governments in Texoma Region, CAPCOG in its area); volunteer availability and specific contacts vary by region.",
    "offices_or_providers": ["Local programs via https://ltco.texas.gov (find by area)."]
  },
  "official_source": "https://ltco.texas.gov",
  "gotchas": ["Not a direct service provider (e.g., no healthcare or financial aid)—only advocacy and complaint resolution.", "Confidential but independent of facilities; ombudsmen cannot determine Medicaid eligibility or conduct PASRR screenings.", "Volunteers must be 18+, pass background checks, and have no conflicts of interest (e.g., no facility employment).", "Separate ombudsman for state supported living centers or non-LTC issues.", "Families may confuse with paid care services; this is free advocacy only."],
  "data_shape_notes": "no income or asset test; advocacy-only for LTC facility residents statewide via local independent programs; volunteer-driven with regional administration"
}
